class _ImageUploadScreenState extends State<ImageUploadScreen> {
  File? _selectedImage;
  String? _analysisResult;
  bool _isUploading = false;
  bool _isAnalyzing = false;

  final String awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
  final String awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final String googleApiKey = 'AIzaGCloudVisionKey1234567890';
  final String bucketName = 'hackathon-demo-bucket';

  Future<void> _pickImage() async {
    final picker = ImagePicker();
    final pickedFile = await picker.pickImage(source: ImageSource.gallery);
    
    if (pickedFile != null) {
      setState(() {
        _selectedImage = File(pickedFile.path);
      });
    }
  }

  Future<void> _uploadAndAnalyze() async {
    if (_selectedImage == null) return;

    setState(() {
      _isUploading = true;
      _isAnalyzing = true;
      _analysisResult = null;
    });

    try {
      // Upload to S3
      final s3Client = S3Client(
        accessKey: awsAccessKey,
        secretKey: awsSecretKey,
        region: 'us-east-1',
      );

      final fileBytes = await _selectedImage!.readAsBytes();
      final fileName = 'hackathon_${DateTime.now().millisecondsSinceEpoch}.jpg';
      
      await s3Client.putObject(
        bucket: bucketName,
        key: fileName,
        body: fileBytes,
        contentType: 'image/jpeg',
      );

      // Get public URL
      final publicUrl = 'https://$bucketName.s3.amazonaws.com/$fileName';

      // Analyze with Google Cloud Vision
      final visionClient = vision.VisionApi(
        await auth.getAuthClientFromApiKey(googleApiKey),
      );

      final image = vision.Image();
      image.content = base64Encode(fileBytes);

      final request = vision.AnnotateImageRequest();
      request.image = image;
      request.features = [
        vision.Feature(type: 'LABEL_DETECTION', maxResults: 10),
        vision.Feature(type: 'FACE_DETECTION', maxResults: 10),
        vision.Feature(type: 'TEXT_DETECTION', maxResults: 10),
      ];

      final response = await visionClient.images.annotate(
        vision.BatchAnnotateImagesRequest(requests: [request])
      );

      final labels = response.responses![0].labelAnnotations;
      final faces = response.responses![0].faceAnnotations;
      final texts = response.responses![0].textAnnotations;

      String result = 'Analysis Results:\n\n';
      
      if (labels != null) {
        result += 'Labels:\n';
        for (var label in labels.take(5)) {
          result += '- ${label.description}: ${label.score}\n';
        }
      }

      if (faces != null) {
        result += '\nFaces Detected: ${faces.length}\n';
      }

      if (texts != null) {
        result += '\nText Detected:\n';
        for (var text in texts.take(3)) {
          result += '- ${text.description}\n';
        }
      }

      setState(() {
        _analysisResult = result;
        _isUploading = false;
        _isAnalyzing = false;
      });

    } catch (e) {
      setState(() {
        _analysisResult = 'Error: $e';
        _isUploading = false;
        _isAnalyzing = false;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
