                fit: BoxFit.cover,
              )
            else
              Container(
                height: 200,
                width: 200,
                decoration: BoxDecoration(
                  border: Border.all(color: Colors.grey),
                ),
                child: Icon(Icons.photo, size: 50, color: Colors.grey),
              ),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: _pickImage,
              child: Text('Select Image'),
            ),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: _selectedImage != null && !_isUploading ? _uploadAndAnalyze : null,
              child: _isUploading 
                ? Text('Uploading...') 
                : Text('Upload & Analyze'),
            ),
            SizedBox(height: 20),
            if (_analysisResult != null)
              Container(
                padding: EdgeInsets.all(16),
                decoration: BoxDecoration(
                  border: Border.all(color: Colors.grey),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Text(_analysisResult!),
              ),
            if (_isAnalyzing)
              CircularProgressIndicator(),
          ],
